# Derived module - tests cross-module inheritance and interface implementation
from types_module import Shape, IDrawable, Color, Point

class Rectangle(Shape, IDrawable):
    """Rectangle inherits from Shape and implements IDrawable"""
    width: float
    height: float
    top_left: Point

    def __init__(self, color: Color, width: float, height: float, top_left: Point):
        super().__init__(color)
        self.width = width
        self.height = height
        self.top_left = top_left

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        base = super().describe()
        return f"{base}, specifically a {self.color.name} rectangle at ({self.top_left.x}, {self.top_left.y})"

    def draw(self) -> str:
        return f"Drawing rectangle: {self.width:.1f} x {self.height:.1f}"

class Circle(Shape, IDrawable):
    """Circle inherits from Shape and implements IDrawable"""
    radius: float
    center: Point

    def __init__(self, color: Color, radius: float, center: Point):
        super().__init__(color)
        self.radius = radius
        self.center = center

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"A {self.color.name} circle with radius {self.radius:.1f} at ({self.center.x}, {self.center.y})"

    def draw(self) -> str:
        return f"Drawing circle: radius {self.radius:.1f}"

def create_red_rectangle() -> Rectangle:
    """Factory function returning cross-module inherited type"""
    origin = Point(0.0, 0.0)
    return Rectangle(Color.RED, 10.0, 5.0, origin)

