# Utility module - tests function imports and module-level constants
from types_module import Color, Point

@static
PI: float = 3.14159

@static
DEFAULT_COLOR: Color = Color.BLUE

def format_measurement(value: float, unit: str) -> str:
    """Format a measurement with units"""
    return f"{value:.2f}{unit}"

def create_origin() -> Point:
    """Factory returning imported struct type"""
    return Point(0.0, 0.0)

def color_to_hex(color: Color) -> str:
    """Convert Color enum to hex string"""
    if color == Color.RED:
        return "#FF0000"
    elif color == Color.GREEN:
        return "#00FF00"
    elif color == Color.BLUE:
        return "#0000FF"
    else:
        return "#FFFF00"
